INSERT INTO `programs` VALUES (1,'1) Information Technology','Affiliated with NIIT Foundation, these 2-3 month courses combine theoretical knowledge with practical proficiency in MS Office, Web designing, and programming fundamentals.','fas fa-laptop-code','assets/images/it.png','Certificate Course in Active Basic IT (CCAB)\nCertificate Course in Advance Word-Excel (CCAWE)\nCertificate Course in IT for Beginners (CCIB)\nCertificate Course in Data Entry Skill (CCDE)','2026-05-18 11:50:37'),(2,'2) Beauty & Lifestyle','Tailored for today\'s industry, these 2-4 month courses blend classroom learning with immersive practical training in grooming and wellness.','fas fa-spa','assets/images/beauty.png','Certificate Course in Makeup & Hair Stylist\nCertificate Course in Nail Extension\nCertificate Course in Skin Therapist\nCertificate Course in Mehendi','2026-05-18 11:50:37'),(3,'3) Fashion & Dress Designing','Career-driven stitching and tailoring courses (3-5 months) that include classroom learning with practical crafting.','fas fa-cut','assets/images/stitching.png','Basic Stitching (Pattern Making, Drafting, Cutting)\nAdvanced Stitching (Designing, Draping, Color Wheel)','2026-05-18 11:50:37'),(4,'4) Soft Skills Training','Technical skills must be complemented with effective communication. These 3-4 month programs include interactive learning, personality building, and presentation techniques, empowering trainees to express themselves confidently.','fas fa-users','assets/images/about_who_we_are.png','Conversation\nVocabulary\nInterview Prep','2026-05-18 11:50:37');
